#include <stdio.h>
#include <math.h>
#include <stdint.h>

static uint64_t modPow(uint64_t base, uint64_t exp, uint64_t mod) {
    __uint128_t result = 1;
    __uint128_t b = base % mod;
    while (exp) {
        if (exp & 1) result = (result * b) % mod;
        b = (b * b) % mod;
        exp >>= 1;
    }
    return (uint64_t)result;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t n; int k;
        scanf("%llu %d", &n, &k);
        // leading digits
        long double x = (long double)n * log10l((long double)n);
        long double intpart;
        long double frac = modfl(x, &intpart);
        long double leading_f = powl(10.0L, frac + k - 1);
        uint64_t leading = (uint64_t)floorl(leading_f + 1e-12L);
        // trailing digits
        uint64_t mod = 1;
        for (int i = 0; i < k; ++i) mod *= 10ULL;
        uint64_t trailing = modPow(n, n, mod);
        // print with leading zeros for trailing part
        char fmt[32];
        sprintf(fmt, "%%llu %%0%dlu\n", k);
        printf(fmt, leading, trailing);
    }
    return 0;
}

