#include <bits/stdc++.h>
using namespace std;
using int64 = long long;
using i128 = __int128_t;

int64 modPow(int64 base, int64 exp, int64 mod) {
    i128 res = 1;
    i128 b = base % mod;
    while (exp) {
        if (exp & 1) res = (res * b) % mod;
        b = (b * b) % mod;
        exp >>= 1;
    }
    return (int64)res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        long long n; int k; cin>>n>>k;
        long double x = (long double)n * log10l((long double)n);
        long double intpart;
        long double frac = modfl(x, &intpart);
        long double leading_f = powl(10.0L, frac + k - 1);
        long long leading = (long long)floorl(leading_f + 1e-12L);
        long long mod = 1;
        for (int i=0;i<k;++i) mod*=10LL;
        long long trailing = modPow(n, n, mod);
        cout << leading << ' ' << setw(k) << setfill('0') << trailing << "\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
import java.math.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; ++tc) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long n = Long.parseLong(st.nextToken());
            int k = Integer.parseInt(st.nextToken());
            // leading digits
            double x = n * Math.log10(n);
            double intPart = Math.floor(x);
            double frac = x - intPart;
            double leadingDouble = Math.pow(10.0, frac + k - 1);
            long leading = (long) Math.floor(leadingDouble + 1e-12);
            // trailing digits
            BigInteger MOD = BigInteger.TEN.pow(k);
            BigInteger base = BigInteger.valueOf(n);
            BigInteger trailingBI = base.modPow(BigInteger.valueOf(n), MOD);
            String trailingStr = trailingBI.toString();
            while (trailingStr.length() < k) trailingStr = "0" + trailingStr;
            out.append(leading).append(' ').append(trailingStr).append('\n');
        }
        System.out.print(out.toString());
    }
}

