const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let result = [];
function modPow(base, exp, mod) {
  let b = BigInt(base) % BigInt(mod);
  let e = BigInt(exp);
  let m = BigInt(mod);
  let res = 1n;
  while (e > 0n) {
    if (e & 1n) res = (res * b) % m;
    b = (b * b) % m;
    e >>= 1n;
  }
  return Number(res);
}
for (let t = 0; t < T; ++t) {
  const n = Number(input[idx++]);
  const k = Number(input[idx++]);
  // leading digits
  const x = n * Math.log10(n);
  const frac = x - Math.floor(x);
  const leading = Math.floor(Math.pow(10, frac + k - 1) + 1e-12);
  // trailing digits
  const mod = 10 ** k;
  const trailingNum = modPow(n, n, mod);
  const trailingStr = trailingNum.toString().padStart(k, '0');
  result.push(`${leading} ${trailingStr}`);
}
